using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var openAiKey  = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
var modelId    = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

if (string.IsNullOrWhiteSpace(openAiKey))
{
    Console.Error.WriteLine("Set the OPENAI_API_KEY environment variable to run this agent.");
    return 1;
}

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook   = new Notebook();
var webSearch  = new WebSearchService();

var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// ---------------------------------------------------------------------------
// Build chat client with automatic function invocation
// ---------------------------------------------------------------------------
IChatClient chatClient = new OpenAIClient(openAiKey)
    .GetChatClient(modelId)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

// ---------------------------------------------------------------------------
// Create the research agent
// ---------------------------------------------------------------------------
const string instructions = """
    You are a research agent. Your job is to thoroughly research a topic the user
    provides and then produce a well-organized summary of your findings.

    Follow this workflow:
    1. Break the topic into 2-3 specific search queries.
    2. For each query, call the SearchWeb tool to retrieve information.
    3. After each search, use AddNote to save the most important facts,
       including the source URL.
    4. Once you have gathered enough material, call GetNotes to review
       everything you collected.
    5. Finally, write a comprehensive summary that synthesizes all notes.
       Include inline source references.

    Be thorough but concise. Prefer facts over opinion.
    """;

ChatClientAgent agent = chatClient.AsAIAgent(
    instructions: instructions,
    name: "ResearchAgent",
    description: "Researches a topic via web search and summarizes findings.",
    tools: tools);

// ---------------------------------------------------------------------------
// Run
// ---------------------------------------------------------------------------
Console.WriteLine("🔍 Research Agent");
Console.WriteLine(new string('─', 50));

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\nResearching: {topic}\n");

AgentResponse response = await agent.RunAsync(topic);

Console.WriteLine(new string('─', 50));
Console.WriteLine(response.Text);
Console.WriteLine(new string('─', 50));

if (notebook.Count > 0)
{
    Console.WriteLine($"\n📝 {notebook.Count} note(s) were collected during research.");
}

return 0;

// ---------------------------------------------------------------------------
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrWhiteSpace(topic))
    {
        Console.Error.WriteLine("No topic provided.");
        Environment.Exit(1);
    }
    return topic;
}

// ═══════════════════════════════════════════════════════════════════════════
// Tool implementations
// ═══════════════════════════════════════════════════════════════════════════

/// <summary>Provides web search capability by scraping Bing search results.</summary>
sealed class WebSearchService
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
            { "Accept-Language", "en-US,en;q=0.9" }
        },
        Timeout = TimeSpan.FromSeconds(15)
    };

    [Description("Searches the web for the given query and returns a list of result snippets with URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query to look up on the web.")] string query,
        [Description("Maximum number of results to return (1-10).")] int maxResults = 5)
    {
        maxResults = Math.Clamp(maxResults, 1, 10);
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);
            var results = ParseSearchResults(html, maxResults);

            if (results.Count == 0)
                return $"No results found for \"{query}\".";

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for \"{query}\":");
            for (int i = 0; i < results.Count; i++)
            {
                var (title, snippet, link) = results[i];
                sb.AppendLine($"\n[{i + 1}] {title}");
                sb.AppendLine($"    URL: {link}");
                sb.AppendLine($"    {snippet}");
            }

            Console.WriteLine($"  ✅ Found {results.Count} result(s)");
            return sb.ToString();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"  ⚠️  Search failed: {ex.Message}");
            return $"Search failed for \"{query}\": {ex.Message}";
        }
    }

    private static List<(string Title, string Snippet, string Url)> ParseSearchResults(
        string html, int max)
    {
        var results = new List<(string, string, string)>();

        // DuckDuckGo HTML results are in <a class="result__a"> for titles
        // and <a class="result__snippet"> for snippets
        var resultBlocks = Regex.Matches(html, @"<div[^>]*class=""[^""]*result[^""]*""[^>]*>(.*?)</div>\s*</div>",
            RegexOptions.Singleline);

        foreach (Match block in resultBlocks)
        {
            if (results.Count >= max) break;

            var content = block.Groups[1].Value;

            var titleMatch = Regex.Match(content, @"<a[^>]*class=""result__a""[^>]*href=""([^""]*)""[^>]*>(.*?)</a>",
                RegexOptions.Singleline);
            var snippetMatch = Regex.Match(content, @"<a[^>]*class=""result__snippet""[^>]*>(.*?)</a>",
                RegexOptions.Singleline);

            if (!titleMatch.Success) continue;

            var rawUrl = titleMatch.Groups[1].Value;
            var title = StripHtml(titleMatch.Groups[2].Value).Trim();
            var snippet = snippetMatch.Success ? StripHtml(snippetMatch.Groups[1].Value).Trim() : "";

            // DuckDuckGo wraps URLs in a redirect; extract the actual URL
            var actualUrl = ExtractDdgUrl(rawUrl);

            if (!string.IsNullOrWhiteSpace(title))
                results.Add((title, snippet, actualUrl));
        }

        return results;
    }

    private static string ExtractDdgUrl(string ddgUrl)
    {
        // DuckDuckGo links look like: //duckduckgo.com/l/?uddg=https%3A%2F%2F...&rut=...
        var match = Regex.Match(ddgUrl, @"uddg=([^&]+)");
        if (match.Success)
